export const stripUndefined = <T extends Record<string, unknown>>(obj: T): Partial<T> =>
  Object.fromEntries(Object.entries(obj).filter(([, v]) => v !== undefined)) as Partial<T>;
```

This replaces the pattern found in 50+ tool files:
```typescript
// BEFORE (manual, 10+ lines per tool):
const body: Record<string, unknown> = { content: params.content };
if (params.description !== undefined) body.description = params.description;
if (params.project_id !== undefined) body.project_id = params.project_id;
if (params.due_string !== undefined) body.due_string = params.due_string;

// AFTER (1 line):
const body = stripUndefined(params);
// Or for partial updates:
const { task_id, ...updates } = params;
const body = stripUndefined(updates);
```

Constraints:
- Do NOT change any existing functions
- Must preserve null, 0, false, '' — only filter undefined
- Return type is Partial<T> to maintain type safety

